-- PRS Intakes Data (from Excel)
-- Generated 2026-07-10T18:57:19.685663
-- Records: 8550

SET NAMES utf8mb4;

CREATE TABLE IF NOT EXISTS prs_intakes_data (
    id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    prs_number VARCHAR(100),
    district VARCHAR(255),
    intake_date VARCHAR(50),
    status VARCHAR(100),
    findings_date VARCHAR(50),
    category VARCHAR(255),
    subcategory VARCHAR(255),
    closure_code VARCHAR(100),
    UNIQUE KEY uq_prs_number (prs_number)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

